// Process Amazon products - filter, enrich, and prepare for AI
const input = $input.all();
const data = input[0].json;
const products = data.deals || data.products || [];
const affiliateTag = $env.AMAZON_AFFILIATE_TAG || 'yourtag-20';
const maxProducts = parseInt($env.MAX_POSTS_PER_RUN || '3');
const language = $env.LANGUAGE || 'en';

// Filter products with good ratings and prepare data
const processed = products
  .filter(p => p.title && p.asin)
  .filter(p => !p.rating || p.rating >= 3.5) // Only good products
  .slice(0, maxProducts)
  .map((p, index) => {
    const price = typeof p.price === 'object' ? p.price.current_price : p.price;
    const currency = typeof p.price === 'object' ? p.price.currency : 'USD';
    const affiliateLink = `https://www.amazon.com/dp/${p.asin}?tag=${affiliateTag}`;

    return {
      index: index + 1,
      asin: p.asin,
      title: p.title,
      price: price || 'Check price',
      currency: currency || 'USD',
      rating: p.rating || 'N/A',
      reviewCount: p.reviews_count || p.review_count || 'many',
      image: p.image || p.thumbnail || '',
      category: p.category || 'General',
      discount: p.discount_percent || p.savings_percent || 0,
      affiliateLink: affiliateLink,
      language: language,
      features: (p.features || []).slice(0, 3).join('. ') || 'Premium quality product'
    };
  });

if (processed.length === 0) {
  throw new Error('No valid products found after filtering');
}

return processed.map(p => ({ json: p }));

// Parse AI response into structured social post + YouTube Shorts data
const input = $input.all();
const aiOutput = input[0].json.output || input[0].json.text || '';
const productData = input[0].json;

function extractSection(text, startTag, endTag) {
  const startIdx = text.indexOf(startTag);
  if (startIdx === -1) return '';
  const contentStart = startIdx + startTag.length;
  const endIdx = endTag ? text.indexOf(endTag, contentStart) : text.length;
  return text.substring(contentStart, endIdx === -1 ? text.length : endIdx).trim();
}

const socialPost = extractSection(aiOutput, '---SOCIAL_POST---', '---SHORTS_HOOK---');
const shortsHook = extractSection(aiOutput, '---SHORTS_HOOK---', '---SHORTS_BODY---');
const shortsBody = extractSection(aiOutput, '---SHORTS_BODY---', '---SHORTS_CTA---');
const shortsCta = extractSection(aiOutput, '---SHORTS_CTA---', '---YOUTUBE_TITLE---');
const youtubeTitle = extractSection(aiOutput, '---YOUTUBE_TITLE---', '---YOUTUBE_DESCRIPTION---');
const youtubeDesc = extractSection(aiOutput, '---YOUTUBE_DESCRIPTION---', '---END---');

const fullScript = `[HOOK - 0-3s]\n${shortsHook}\n\n[BODY - 3-25s]\n${shortsBody}\n\n[CTA - 25-30s]\n${shortsCta}`;

return [{
  json: {
    // Product data (pass through)
    asin: productData.asin,
    title: productData.title,
    price: productData.price,
    affiliateLink: productData.affiliateLink,
    image: productData.image,

    // Social media content
    socialPost: socialPost,

    // YouTube Shorts content
    shortsHook: shortsHook,
    shortsBody: shortsBody,
    shortsCta: shortsCta,
    shortsFullScript: fullScript,
    youtubeTitle: youtubeTitle.substring(0, 70),
    youtubeDescription: youtubeDesc,

    // Metadata
    language: productData.language || 'en',
    generatedAt: new Date().toISOString()
  }
}];

