// Save YouTube Shorts script data for video creation
const input = $input.all();
const item = input[0].json;

// Prepare data for YouTube upload or manual video creation
const youtubeData = {
  title: item.youtubeTitle,
  description: item.youtubeDescription,
  script: item.shortsFullScript,
  hook: item.shortsHook,
  body: item.shortsBody,
  cta: item.shortsCta,
  product: {
    name: item.title,
    price: item.price,
    link: item.affiliateLink,
    image: item.image
  },
  tags: [
    'amazon finds', 'amazon deals', 'amazon must haves',
    'best amazon products', item.title.split(' ').slice(0, 3).join(' ')
  ],
  metadata: {
    categoryId: '22',
    privacyStatus: 'public',
    madeForKids: false,
    language: item.language,
    generatedAt: item.generatedAt
  }
};

return [{ json: youtubeData }];
